import ExcelViewer from 'polaris-excel-viewer'
import { XMindEmbedViewer } from 'polaris-xmind-viewer'
import { renderAsync, renderDocument } from 'polaris-docx-preview'

export function renderExcel(dom: any, url: string | File, opts?: any) {
  if (typeof url !== 'string') {
    url = URL.createObjectURL(url)
  }
  return new ExcelViewer(dom, url, {
    readonly: true,
    disabled: true,
    ...(opts || {}),
  })
}

export function renderDoc(blob: File, dom: any) {
  return renderAsync(blob, dom)
}

export function renderXMind(blob: ArrayBuffer, dom: any, opts?: any) {
  return new XMindEmbedViewer({
    el: dom,
    file: blob,
    ...(opts || {}),
  })
}
